class GeminiImageApiClient:
    """基于 Gemini API 的分镜配图生成客户端。完全通过官方 API 调用。"""

    # 可用环境变量覆盖，便于不同账号地区使用实际开通的图像模型。
    MODEL_NAME = os.environ.get("GEMINI_IMAGE_MODEL", "gemini-3-pro-image-preview")

    @staticmethod
    def _extract_image_bytes(response):
        """从 google-genai 的响应中尽量提取第一张图片的二进制数据。"""
        candidates = getattr(response, "candidates", None) or []
        for cand in candidates:
            content = getattr(cand, "content", None)
            parts = getattr(content, "parts", None) or []
            for part in parts:
                inline_data = getattr(part, "inline_data", None)
                if inline_data:
                    mime_type = getattr(inline_data, "mime_type", "") or ""
                    data = getattr(inline_data, "data", None)
                    if data and mime_type.startswith("image/"):
                        if isinstance(data, bytes):
                            return data, mime_type
                        if isinstance(data, str):
                            return base64.b64decode(data), mime_type
        # 部分 SDK 版本可能把 parts 放在 response.content 下。

        content = getattr(response, "content", None)
        parts = getattr(content, "parts", None) or []
        for part in parts:
            inline_data = getattr(part, "inline_data", None)
            if inline_data:
                mime_type = getattr(inline_data, "mime_type", "") or ""
                data = getattr(inline_data, "data", None)
                if data and mime_type.startswith("image/"):
                    if isinstance(data, bytes):
                        return data, mime_type
                    if isinstance(data, str):
                        return base64.b64decode(data), mime_type
        return None, ""

