def _sample_text_across_full_range_for_visual_lock(text: str, max_chars: int = 3600) -> str:
    """从章节全文开头/中段/结尾取样，给 A/C 视觉摘要提供全局依据。"""
    raw = str(text or "").replace("\r\n", "\n").replace("\r", "\n")
    raw = re.sub(r"!\[[^\]]*\]\([^\)]*\)", " ", raw)
    raw = re.sub(r"<[^>]{1,120}>", " ", raw)
    raw = re.sub(r"\n{3,}", "\n\n", raw)
    raw = re.sub(r"[ \t]{2,}", " ", raw).strip()
    if len(raw) <= max_chars:
        return raw
    part = max(400, max_chars // 3)
    mid = max(0, len(raw) // 2 - part // 2)
    pieces = [raw[:part], raw[mid:mid + part], raw[-part:]]
    return "\n\n[...]\n\n".join(x.strip() for x in pieces if x.strip())[:max_chars]


def _extract_visual_lock_sentences(text: str, limit: int = 900) -> str:
    """保守抽取章节内真正含结构/机制/证据的句子，避免把 A/C 退化为空泛壁纸。"""
    raw = str(text or "")
    if not raw.strip():
        return ""
    raw = re.sub(r"[`*_>#\[\](){}/\\|]", " ", raw)
    raw = re.sub(r"\s+", " ", raw).strip()
    parts = re.split(r"(?<=[。！？；;.!?])\s+|\n+", raw)
    content_re = re.compile(
        r"(机制|结构|功能|过程|证据|实验|观察|比较|变化|影响|调节|导致|参与|支持|说明|显示|表明|"
        r"细胞|分子|蛋白|受体|通道|递质|突触|神经元|轴突|树突|髓鞘|环路|通路|网络|脑区|皮层|丘脑|海马|杏仁核|小脑|脑干|"
        r"免疫|炎症|感染|血管|心脏|肺|肝|肾|胃|肠|激素|代谢|肿瘤|疾病|损伤|行为|认知|学习|记忆|感知|运动|意识|"
        r"cell|neuron|synapse|receptor|channel|circuit|pathway|cortex|hippocampus|evidence|experiment|mechanism|function|structure)",
        flags=re.I,
    )
    bad_re = re.compile(r"(关注|点赞|收藏|转发|欢迎|本视频|下一章继续|请基于|输出格式|不要输出|Prompt|Negative Prompt|Page Type)", flags=re.I)
    chosen = []
    for s in parts:
        s = s.strip(" ，,。；;：:\t")
        if len(s) < 18 or len(s) > 260:
            continue
        if bad_re.search(s):
            continue
        if not content_re.search(s):
            continue
        if s not in chosen:
            chosen.append(s)
        if len("；".join(chosen)) >= limit:
            break
    if not chosen:
        fallback = raw[:limit].strip(" ，,。；;：:")
        return fallback
    merged = "；".join(chosen)
    return merged[:limit].rstrip(" ，,。；;：:")


def build_chapter_visual_summary_lock(
    *,
    voiceover_text: str = "",
    source_text: str = "",
    chapter_title_cn: str = "",
    chapter_number: str = "",
    next_theme: str = "",
    next_guidance: dict | None = None,
) -> str:
    """生成给 A1/A2/A01/A02/C 使用的全章视觉摘要锁，不额外调用模型。"""
    title = clean_chapter_title_translation_text(chapter_title_cn, fallback=chapter_title_cn) if 'clean_chapter_title_translation_text' in globals() else str(chapter_title_cn or "").strip()
    try:
        global_theme = _summarize_global_script_theme(voiceover_text or "", limit=900)
    except Exception:
        global_theme = _extract_visual_lock_sentences(voiceover_text, limit=900)
    sampled_source = _sample_text_across_full_range_for_visual_lock(source_text, max_chars=5200)
    source_evidence = _extract_visual_lock_sentences(sampled_source, limit=1200)
    source_len = len(str(source_text or ""))
    guide = next_guidance or {}
    verified_next = str(guide.get("mechanism_preview") or guide.get("relevance_example") or "").strip()
    has_next = bool(guide.get("has_verified_source"))
    try:
        anchor_text = _voiceover_visual_keywords((global_theme or "") + "\n" + (source_evidence or ""))
    except Exception:
        anchor_text = ""
    if not anchor_text:
        anchor_text = _voiceover_visual_keywords(str(voiceover_text or "")) if '_voiceover_visual_keywords' in globals() else ""
    relation_text = ""
    try:
        relation_text = _voiceover_logic_relation_brief((global_theme or "") + "\n" + (source_evidence or ""))
    except Exception:
        relation_text = ""
    lines = []
    lines.append("FULL-CHAPTER VISUAL SUMMARY LOCK / 全章视觉摘要锁")
    if chapter_number or title:
        lines.append(f"Chapter: {chapter_number} {title}".strip())
    if global_theme:
        lines.append(f"Chapter-level voiceover summary: {global_theme}")
    if source_evidence:
        lines.append(f"Full parsed chapter evidence summary sampled from beginning / middle / end ({source_len:,} chars): {source_evidence}")
    if anchor_text:
        lines.append(f"Concrete biomedical anchors that should visibly appear as real subjects rather than generic symbols: {anchor_text}")
    if relation_text:
        lines.append(f"Dominant chapter-level relationship to visualize: {relation_text}")
    if next_theme:
        if has_next and verified_next:
            lines.append(f"Verified next-question bridge for C page: {next_theme}；{verified_next}")
        else:
            lines.append(f"Next-question bridge for C page: {next_theme}；title-level only, do not invent mechanisms, scenes, diseases, experiments or examples.")
    lines.append("A-series requirement: A1/A2/A01/A02 must use one shared no-text master background that visually summarizes this whole chapter: core object -> central question/tension -> mechanism/evidence chain -> conclusion boundary. No labels, no letters, no numbers, no logo, no watermark, and no pseudo-text.")
    lines.append("Mandatory visual richness for A-series: do not reduce the chapter to one floating symbol. Show at least 3 concrete, source-supported visual components in one integrated composition, such as anatomical structure + cellular or molecular mechanism + evidence/experimental or state-change cue. If the chapter supports multiple scales, make the scale relationship visible.")
    lines.append("C-page requirement: C background must visually recap the same chapter-level relationship and only open toward the verified/title-level next question; it must not become generic brand atmosphere. C raw background is also no-text: no labels, no letters, no numbers, no logo, no watermark, and no pseudo-text.")
    lines.append("Mandatory composition rule: use relationship-first spatial organization such as sequence, comparison, pathway, hierarchy, evidence-to-claim, input-output, or problem-to-explanation. A single generic brain, neuron, DNA helix, molecule icon, or soft blue wallpaper is not acceptable.")
    lines.append("Hard ban: no generic brain/neuron/DNA/cell wallpaper, no abstract medical background, no soft particles, no unrelated decorative biology symbol, no empty brand backdrop.")
    return "\n".join(x for x in lines if str(x).strip()).strip()



