def _image_prompt_pair_role_name(name: str, prompt: str = "") -> str:
    combined = f"{name}\n{prompt}"
    if re.search(r"A1|Master|WeChat\s*Cover|封面", combined, flags=re.I):
        return "a_master"
    if re.search(r"A2|A01|A02|Home|Bilibili|首页|B站", combined, flags=re.I):
        return "a_derived"
    if re.search(r"\bC\b|Brand|Final|Ending|品牌|尾页|结束", combined, flags=re.I):
        return "c"
    return "b"



def _cap_extracted_prompt_pair(name: str, prompt: str) -> tuple[str, str]:
    """解析出单张提示词后先限制长度，避免后续流程读到超长旧模板。

    保留 Page Type 换行，防止后续重建 A/B/C 槽位时误删同一行上的正文。
    """
    body = str(prompt or "").strip()
    if '_normalize_prompt_page_type_newline' in globals():
        try:
            body = _normalize_prompt_page_type_newline(body)
        except Exception:
            pass
    body = re.sub(r"[^\S\n]+", " ", body).strip()
    if not body:
        return name, body
    if '_limit_saved_image_prompt_text' in globals():
        try:
            body = _limit_saved_image_prompt_text(body, name=name)
        except Exception:
            pass
    return name, body


def _cap_extracted_prompt_pairs(pairs: list[tuple[str, str]]) -> list[tuple[str, str]]:
    return [_cap_extracted_prompt_pair(name, prompt) for name, prompt in (pairs or [])]


